  1→use std::io::Write;
  2→use std::path::{Path, PathBuf};
  3→use std::process::{ExitCode, Stdio};
  4→
  5→use jj_lib::config::StackedConfig;
  6→use jj_lib::hex_util::encode_reverse_hex;
  7→use jj_lib::object_id::ObjectId;
  8→use jj_lib::repo::{Repo, StoreFactories};
  9→use jj_lib::revset::{RevsetExpression, SymbolResolver};
 10→use jj_lib::settings::UserSettings;
 11→use jj_lib::workspace::{Workspace, default_working_copy_factories};
 12→use pollster::FutureExt;
 13→
 14→const USAGE: &str = "\
 15→Usage: vc-x1 [OPTIONS] <COMMAND>
 16→
 17→Commands:
 18→  list [<path>]       List commits in a jj repo (defaults to current directory)
 19→  finalize [OPTIONS]  Squash working copy into target commit (daemonizes by default)
 20→
 21→Options:
 22→  -V, --version  Print version
 23→  -h, --help     Print this help message";
 24→
 25→const FINALIZE_USAGE: &str = "\
 26→Usage: vc-x1 finalize [OPTIONS]
 27→
 28→Squash source revision into target revision, optionally push afterward.
 29→By default, daemonizes and returns immediately.
 30→
 31→Options:
 32→  --repo <path>      Path to jj repo (default: current directory)
 33→  --source <revset>  Source revision to squash (default: @)
 34→  --target <revset>  Target revision to squash into (default: @-)
 35→  --delay <seconds>  Seconds to wait before squashing (default: 1)
 36→  --push             Push after squashing
 37→  --log <path>       Log file path (default: /tmp/vc-x1-finalize-<timestamp-millis>.log)
 38→  --foreground       Run in foreground instead of daemonizing
 39→  -h, --help         Print this help message";
 40→
 41→#[derive(Debug, PartialEq)]
 42→enum Command {
 43→    Version,
 44→    Help,
 45→    FinalizeHelp,
 46→    List { path: PathBuf },
 47→    Finalize(FinalizeOpts),
 48→}
 49→
 50→#[derive(Debug, PartialEq)]
 51→struct FinalizeOpts {
 52→    repo: PathBuf,
 53→    source: String,
 54→    target: String,
 55→    delay_secs: f64,
 56→    push: bool,
 57→    log: PathBuf,
 58→    foreground: bool,
 59→    exec: bool,
 60→}
 61→
 62→impl Default for FinalizeOpts {
 63→    fn default() -> Self {
 64→        Self {
 65→            repo: PathBuf::from("."),
 66→            source: "@".to_string(),
 67→            target: "@-".to_string(),
 68→            delay_secs: 1.0,
 69→            push: false,
 70→            log: PathBuf::from(format!(
 71→                "/tmp/vc-x1-finalize-{}.log",
 72→                std::time::SystemTime::now()
 73→                    .duration_since(std::time::UNIX_EPOCH)
 74→                    .unwrap_or_default()
 75→                    .as_millis()
 76→            )),
 77→            foreground: false,
 78→            exec: false,
 79→        }
 80→    }
 81→}
 82→
 83→fn parse_finalize_args<I>(args: &mut I) -> Result<Command, String>
 84→where
 85→    I: Iterator<Item = String>,
 86→{
 87→    let mut opts = FinalizeOpts::default();
 88→
 89→    while let Some(arg) = args.next() {
 90→        match arg.as_str() {
 91→            "--help" | "-h" => return Ok(Command::FinalizeHelp),
 92→            "--repo" => {
 93→                opts.repo = PathBuf::from(
 94→                    args.next()
 95→                        .ok_or_else(|| "--repo requires a value".to_string())?,
 96→                );
 97→            }
 98→            "--source" => {
 99→                opts.source = args
100→                    .next()
101→                    .ok_or_else(|| "--source requires a value".to_string())?;
102→            }
103→            "--target" => {
104→                opts.target = args
105→                    .next()
106→                    .ok_or_else(|| "--target requires a value".to_string())?;
107→            }
108→            "--delay" => {
109→                let val = args
110→                    .next()
111→                    .ok_or_else(|| "--delay requires a value".to_string())?;
112→                opts.delay_secs = val
113→                    .parse()
114→                    .map_err(|_| format!("invalid delay value: {val}"))?;
115→            }
116→            "--push" => opts.push = true,
117→            "--log" => {
118→                opts.log = PathBuf::from(
119→                    args.next()
120→                        .ok_or_else(|| "--log requires a value".to_string())?,
121→                );
122→            }
123→            "--foreground" => opts.foreground = true,
124→            "--exec" => opts.exec = true,
125→            other => {
126→                return Err(format!(
127→                    "unknown finalize option: {other}\n\n{FINALIZE_USAGE}"
128→                ));
129→            }
130→        }
131→    }
132→
133→    Ok(Command::Finalize(opts))
134→}
135→
136→fn parse_args<I>(args: I) -> Result<Command, String>
137→where
138→    I: IntoIterator<Item = String>,
139→{
140→    let mut args = args.into_iter();
141→    let _program = args.next();
142→
143→    match args.next().as_deref() {
144→        Some("--version" | "-V") => Ok(Command::Version),
145→        Some("--help" | "-h" | "help") => Ok(Command::Help),
146→        Some("list") => {
147→            let path = match args.next() {
148→                Some(p) => PathBuf::from(p),
149→                None => std::env::current_dir().map_err(|e| e.to_string())?,
150→            };
151→            Ok(Command::List { path })
152→        }
153→        Some("finalize") => parse_finalize_args(&mut args),
154→        Some(other) => Err(format!("unknown command: {other}\n\n{USAGE}")),
155→        None => Ok(Command::Help),
156→    }
157→}
158→
159→fn list(path: &Path) -> Result<(), Box<dyn std::error::Error>> {
160→    let config = StackedConfig::with_defaults();
161→    let settings = UserSettings::from_config(config)?;
162→    let store_factories = StoreFactories::default();
163→    let working_copy_factories = default_working_copy_factories();
164→
165→    let workspace = Workspace::load(&settings, path, &store_factories, &working_copy_factories)?;
166→    let repo = workspace.repo_loader().load_at_head().block_on()?;
167→
168→    let expression = RevsetExpression::all();
169→    let no_extensions: &[Box<dyn jj_lib::revset::SymbolResolverExtension>] = &[];
170→    let symbol_resolver = SymbolResolver::new(repo.as_ref(), no_extensions);
171→    let resolved = expression.resolve_user_expression(repo.as_ref(), &symbol_resolver)?;
172→    let revset = resolved.evaluate(repo.as_ref())?;
173→
174→    let root_commit_id = repo.store().root_commit_id().clone();
175→
176→    for result in revset.iter() {
177→        let commit_id = result?;
178→        if commit_id == root_commit_id {
179→            continue;
180→        }
181→        let commit = repo.store().get_commit(&commit_id)?;
182→
183→        let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
184→        let change_short = &change_hex[..change_hex.len().min(12)];
185→
186→        let commit_hex = commit.id().hex();
187→        let commit_short = &commit_hex[..commit_hex.len().min(12)];
188→
189→        let first_line = commit.description().lines().next().unwrap_or("");
190→
191→        println!("{} {} {}", change_short, commit_short, first_line);
192→    }
193→
194→    Ok(())
195→}
196→
197→fn log_msg(log: &Path, msg: &str) {
198→    let nanos = std::time::SystemTime::now()
199→        .duration_since(std::time::UNIX_EPOCH)
200→        .unwrap_or_default()
201→        .as_nanos();
202→    let pid = std::process::id();
203→    let line = format!("[{nanos}] pid={pid} {msg}\n");
204→    if let Ok(mut f) = std::fs::OpenOptions::new()
205→        .create(true)
206→        .append(true)
207→        .open(log)
208→    {
209→        let _ = f.write_all(line.as_bytes());
210→    }
211→}
212→
213→fn run_jj(args: &[&str], log: &Path) -> Result<(), Box<dyn std::error::Error>> {
214→    let args_str = args.join(" ");
215→    log_msg(log, &format!("run_jj: jj {args_str}"));
216→    let output = std::process::Command::new("jj")
217→        .args(args)
218→        .output()
219→        .map_err(|e| format!("failed to run jj: {e}"))?;
220→    let stdout = String::from_utf8_lossy(&output.stdout);
221→    let stderr = String::from_utf8_lossy(&output.stderr);
222→    if !stdout.is_empty() {
223→        log_msg(log, &format!("run_jj: stdout: {stdout}"));
224→    }
225→    if !stderr.is_empty() {
226→        log_msg(log, &format!("run_jj: stderr: {stderr}"));
227→    }
228→    if !output.status.success() {
229→        return Err(format!("jj {args_str} failed (exit {}): {stderr}", output.status).into());
230→    }
231→    Ok(())
232→}
233→
234→fn finalize_exec(opts: &FinalizeOpts) -> Result<(), Box<dyn std::error::Error>> {
235→    log_msg(&opts.log, &format!("finalize_exec: starting opts={opts:?}"));
236→
237→    // Sleep to let trailing writes settle
238→    let delay = std::time::Duration::from_secs_f64(opts.delay_secs);
239→    log_msg(&opts.log, &format!("finalize_exec: sleeping {delay:?}"));
240→    std::thread::sleep(delay);
241→
242→    // Squash source into target
243→    let repo_str = opts.repo.to_string_lossy();
244→    run_jj(
245→        &[
246→            "squash",
247→            "--ignore-immutable",
248→            "--use-destination-message",
249→            "--from",
250→            &opts.source,
251→            "--into",
252→            &opts.target,
253→            "-R",
254→            &repo_str,
255→        ],
256→        &opts.log,
257→    )?;
258→
259→    if opts.push {
260→        // Advance main bookmark to target, then push
261→        run_jj(
262→            &[
263→                "bookmark",
264→                "set",
265→                "main",
266→                "-r",
267→                &opts.target,
268→                "-R",
269→                &repo_str,
270→            ],
271→            &opts.log,
272→        )?;
273→        run_jj(&["git", "push", "-R", &repo_str], &opts.log)?;
274→    }
275→
276→    log_msg(&opts.log, "finalize_exec: done");
277→    Ok(())
278→}
279→
280→fn build_exec_args(opts: &FinalizeOpts) -> Vec<String> {
281→    let mut args = vec![
282→        "finalize".to_string(),
283→        "--exec".to_string(),
284→        "--repo".to_string(),
285→        opts.repo.to_string_lossy().to_string(),
286→        "--source".to_string(),
287→        opts.source.clone(),
288→        "--target".to_string(),
289→        opts.target.clone(),
290→        "--delay".to_string(),
291→        opts.delay_secs.to_string(),
292→        "--log".to_string(),
293→        opts.log.to_string_lossy().to_string(),
294→    ];
295→    if opts.push {
296→        args.push("--push".to_string());
297→    }
298→    args
299→}
300→
301→/// Spawn a detached child process with `--exec` and return immediately.
302→/// The child re-enters `main()`, parses `--exec`, and `finalize()` routes
303→/// it to `finalize_exec()` where the actual work happens.
304→fn daemonize(opts: &FinalizeOpts) -> Result<(), Box<dyn std::error::Error>> {
305→    log_msg(
306→        &opts.log,
307→        &format!("daemonize: parent starting opts={opts:?}"),
308→    );
309→
310→    let exe = std::env::current_exe()?;
311→    let args = build_exec_args(opts);
312→    log_msg(&opts.log, &format!("daemonize: exe={exe:?} args={args:?}"));
313→
314→    let mut cmd = std::process::Command::new(exe);
315→    cmd.args(&args).stdin(Stdio::null());
316→
317→    #[cfg(unix)]
318→    {
319→        use std::os::unix::process::CommandExt;
320→        unsafe {
321→            cmd.pre_exec(|| {
322→                libc::setsid();
323→                Ok(())
324→            });
325→        }
326→    }
327→
328→    let child = cmd.spawn()?;
329→    log_msg(
330→        &opts.log,
331→        &format!("daemonize: spawned child pid={}", child.id()),
332→    );
333→    eprintln!(
334→        "finalize: daemonized (pid {}), log: {}",
335→        child.id(),
336→        opts.log.display()
337→    );
338→    Ok(())
339→}
340→
341→fn finalize(opts: &FinalizeOpts) -> Result<(), Box<dyn std::error::Error>> {
342→    log_msg(&opts.log, &format!("finalize: entry opts={opts:?}"));
343→    let result = if opts.foreground || opts.exec {
344→        finalize_exec(opts)
345→    } else {
346→        daemonize(opts)
347→    };
348→    match &result {
349→        Ok(()) => log_msg(&opts.log, "finalize: exit ok"),
350→        Err(e) => log_msg(&opts.log, &format!("finalize: exit err={e}")),
351→    }
352→    result
353→}
354→
355→fn main() -> ExitCode {
356→    let cmd = match parse_args(std::env::args()) {
357→        Ok(cmd) => cmd,
358→        Err(e) => {
359→            eprintln!("error: {e}");
360→            return ExitCode::FAILURE;
361→        }
362→    };
363→
364→    match cmd {
365→        Command::Version => {
366→            println!("vc-x1 {}", env!("CARGO_PKG_VERSION"));
367→            ExitCode::SUCCESS
368→        }
369→        Command::Help => {
370→            println!("{USAGE}");
371→            ExitCode::SUCCESS
372→        }
373→        Command::FinalizeHelp => {
374→            println!("{FINALIZE_USAGE}");
375→            ExitCode::SUCCESS
376→        }
377→        Command::List { path } => {
378→            if let Err(e) = list(&path) {
379→                eprintln!("error: {e}");
380→                return ExitCode::FAILURE;
381→            }
382→            ExitCode::SUCCESS
383→        }
384→        Command::Finalize(opts) => {
385→            log_msg(&opts.log, "main: finalize entry");
386→            match finalize(&opts) {
387→                Ok(()) => {
388→                    log_msg(&opts.log, "main: finalize exit ok");
389→                    ExitCode::SUCCESS
390→                }
391→                Err(e) => {
392→                    log_msg(&opts.log, &format!("main: finalize exit err={e}"));
393→                    eprintln!("error: {e}");
394→                    ExitCode::FAILURE
395→                }
396→            }
397→        }
398→    }
399→}
