            Ok(Command::Finalize(FinalizeOpts {
                repo: PathBuf::from(".claude"),
                source: "@".to_string(),
                target: "@-".to_string(),
                delay_secs: 2.5,
                push: true,
                log: PathBuf::from("/tmp/test.log"),
                foreground: true,
                exec: false,
