234→fn finalize_exec(opts: &FinalizeOpts) -> Result<(), Box<dyn std::error::Error>> {
235→    log_msg(&opts.log, &format!("finalize_exec: starting opts={opts:?}"));
236→
237→    // Sleep to let trailing writes settle
238→    let delay = std::time::Duration::from_secs_f64(opts.delay_secs);
239→    log_msg(&opts.log, &format!("finalize_exec: sleeping {delay:?}"));
240→    std::thread::sleep(delay);
241→
242→    // Squash source into target
243→    let repo_str = opts.repo.to_string_lossy();
244→    run_jj(
245→        &[
246→            "squash",
247→            "--ignore-immutable",
248→            "--use-destination-message",
249→            "--from",
250→            &opts.source,
251→            "--into",
252→            &opts.target,
253→            "-R",
254→            &repo_str,
255→        ],
256→        &opts.log,
257→    )?;
258→
259→    if opts.push {
