261→        run_jj(
262→            &[
263→                "bookmark",
264→                "set",
265→                "main",
266→                "-r",
267→                &opts.target,
268→                "-R",
269→                &repo_str,
270→            ],
271→            &opts.log,
272→        )?;
273→        run_jj(&["git", "push", "-R", &repo_str], &opts.log)?;
274→    }
275→
276→    log_msg(&opts.log, "finalize_exec: done");
277→    Ok(())
278→}
