use std::path::Path;

use jj_lib::index::PrefixResolution;
use jj_lib::object_id::HexPrefix;
use jj_lib::repo::Repo;

use crate::common;

pub const USAGE: &str = "\
Usage: vc-x1 desc <chid> [OPTIONS]

Display the full description of a commit identified by its changeID.

Arguments:
  <chid>            The jj changeID (or prefix) to look up

Options:
  --repo <path>     Path to jj repo (default: current directory)
  -h, --help        Print this help message";

pub fn desc(chid: &str, repo_path: &Path) -> Result<(), Box<dyn std::error::Error>> {
    let (_workspace, repo) = common::load_repo(repo_path)?;

    let prefix = HexPrefix::try_from_reverse_hex(chid)
        .ok_or_else(|| format!("invalid changeID: {chid}"))?;

    let resolution = repo.resolve_change_id_prefix(&prefix)?;

    match resolution {
        PrefixResolution::SingleMatch(targets) => {
            let commit_ids = targets.into_visible();
            if commit_ids.is_empty() {
                return Err(format!("changeID {chid} has no visible commits").into());
            }
            for commit_id in &commit_ids {
                let commit = repo.store().get_commit(commit_id)?;
                let desc = commit.description();
                if desc.is_empty() {
                    println!("(no description set)");
                } else {
                    print!("{desc}");
                }
            }
            Ok(())
        }
        PrefixResolution::AmbiguousMatch => {
            Err(format!("changeID prefix {chid} is ambiguous").into())
        }
        PrefixResolution::NoMatch => Err(format!("no commit found for changeID {chid}").into()),
    }
}

